{
  "files": [
    {
      "path": "README.md",
      "content": "This is a simple Node.js project that provides a REST API for managing TODO items. The API is implemented using only Node.js built-in modules and does not rely on any external dependencies. The project includes endpoints for health checks, retrieving the OpenAPI specification, managing TODO items, and more."
    },
    {
      "path": "package.json",
      "content": "{
  "name": "todo-api",
  "version": "1.0.0",
  "description": "A simple REST API for managing TODO items using Node.js built-in modules.",
  "main": "src/server.js",
  "type": "commonjs",
  "scripts": {
    "start": "node src/server.js"
  }
}"
    },
    {
      "path": "openapi.json",
      "content": "{
  "openapi": "3.0.0",
  "info": {
    "title": "TODO API",
    "version": "1.0.0"
  },
  "servers": [
    {
      "url": "http://localhost:3000"
    }
  ],
  "paths": {
    "/health": {
      "get": {
        "summary": "Check the health of the server",
        "responses": {
          "200": {
            "description": "Server is healthy",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "ok": {
                      "type": "boolean"
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/openapi.json": {
      "get": {
        "summary": "Retrieve the OpenAPI specification",
        "responses": {
          "200": {
            "description": "OpenAPI specification",
            "content": {
              "application/json": {}
            }
          }
        }
      }
    },
    "/todos": {
      "get": {
        "summary": "Retrieve all TODO items",
        "responses": {
          "200": {
            "description": "List of TODO items",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "ok": {
                      "type": "boolean"
                    },
                    "todos": {
                      "type": "array",
                      "items": {
                        "$ref": "#/components/schemas/Todo"
                      }
                    }
                  }
                }
              }
            }
          }
        }
      },
      "post": {
        "summary": "Create a new TODO item",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "title": {
                    "type": "string"
                  }
                },
                "required": ["title"]
              }
            }
          }
        },
        "responses": {
          "201": {
            "description": "TODO item created",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "ok": {
                      "type": "boolean"
                    },
                    "todo": {
                      "$ref": "#/components/schemas/Todo"
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/todos/{id}": {
      "get": {
        "summary": "Retrieve a specific TODO item",
        "parameters": [
          {
            "name": "id",
            "in": "path",
            "required": true,
            "schema": {
              "type": "string"
            }
          }
        ],
        "responses": {
          "200": {
            "description": "TODO item",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "ok": {
                      "type": "boolean"
                    },
                    "todo": {
                      "$ref": "#/components/schemas/Todo"
                    }
                  }
                }
              }
            }
          },
          "404": {
            "description": "TODO item not found",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "ok": {
                      "type": "boolean"
                    },
                    "error": {
                      "type": "string"
                    }
                  }
                }
              }
            }
          }
        }
      },
      "patch": {
        "summary": "Update a specific TODO item",
        "parameters": [
          {
            "name": "id",
            "in": "path",
            "required": true,
            "schema": {
              "type": "string"
            }
          }
        ],
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "done": {
                    "type": "boolean"
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "TODO item updated",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "ok": {
                      "type": "boolean"
                    },
                    "todo": {
                      "$ref": "#/components/schemas/Todo"
                    }
                  }
                }
              }
            }
          }
        }
      },
      "delete": {
        "summary": "Delete a specific TODO item",
        "parameters": [
          {
            "name": "id",
            "in": "path",
            "required": true,
            "schema": {
              "type": "string"
            }
          }
        ],
        "responses": {
          "200": {
            "description": "TODO item deleted",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "ok": {
                      "type": "boolean"
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  },
  "components": {
    "schemas": {
      "Todo": {
        "type": "object",
        "properties": {
          "id": {
            "type": "string"
          },
          "title": {
            "type": "string"
          },
          "done": {
            "type": "boolean"
          },
          "createdAt": {
            "type": "string",
            "format": "date-time"
          },
          "doneAt": {
            "type": "string",
            "format": "date-time",
            "nullable": true
          }
        }
      }
    }
  }
}"
    },
    {
      "path": "src/server.js",
      "content": "const fs = require('node:fs');
const path = require('node:path');
const http = require('node:http');
const crypto = require('node:crypto');
const { parse } = require('node:url');
const { fileURLToPath } = require('node:url');

function createServer({ dataPath }) {
  const server = http.createServer((req, res) => {
    const { pathname, query } = parse(req.url, true);
    const method = req.method;

    if (pathname === '/health' && method === 'GET') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ok: true }));
      return;
    }

    if (pathname === '/openapi.json' && method === 'GET') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(fs.readFileSync(path.join(__dirname, '../openapi.json')));
      return;
    }

    if (pathname === '/todos' && method === 'GET') {
      let todos = [];
      if (fs.existsSync(dataPath)) {
        todos = JSON.parse(fs.readFileSync(dataPath));
      }
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ok: true, todos }));
      return;
    }

    if (pathname === '/todos' && method === 'POST') {
      let body = '';
      req.on('data', chunk => {
        body += chunk.toString();
      });
      req.on('end', () => {
        const todo = JSON.parse(body);
        todo.id = crypto.randomUUID();
        todo.createdAt = new Date().toISOString();
        todo.done = false;
        let todos = [];
        if (fs.existsSync(dataPath)) {
          todos = JSON.parse(fs.readFileSync(dataPath));
        }
        todos.push(todo);
        fs.writeFileSync(dataPath, JSON.stringify(todos));
        res.writeHead(201, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true, todo }));
      });
      return;
    }

    if (pathname.startsWith('/todos/') && method === 'GET') {
      const id = pathname.split('/').pop();
      let todos = [];
      if (fs.existsSync(dataPath)) {
        todos = JSON.parse(fs.readFileSync(dataPath));
      }
      const todo = todos.find(t => t.id === id);
      if (todo) {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true, todo }));
      } else {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: false, error: 'TODO item not found' }));
      }
      return;
    }

    if (pathname.startsWith('/todos/') && method === 'PATCH') {
      const id = pathname.split('/').pop();
      let body = '';
      req.on('data', chunk => {
        body += chunk.toString();
      });
      req.on('end', () => {
        const update = JSON.parse(body);
        let todos = [];
        if (fs.existsSync(dataPath)) {
          todos = JSON.parse(fs.readFileSync(dataPath));
        }
        const todoIndex = todos.findIndex(t => t.id === id);
        if (todoIndex !== -1) {
          const todo = todos[todoIndex];
          if (update.done !== undefined) {
            todo.done = update.done;
            if (todo.done) {
              todo.doneAt = new Date().toISOString();
            }
          }
          fs.writeFileSync(dataPath, JSON.stringify(todos));
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, todo }));
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, error: 'TODO item not found' }));
        }
      });
      return;
    }

    if (pathname.startsWith('/todos/') && method === 'DELETE') {
      const id = pathname.split('/').pop();
      let todos = [];
      if (fs.existsSync(dataPath)) {
        todos = JSON.parse(fs.readFileSync(dataPath));
      }
      const todoIndex = todos.findIndex(t => t.id === id);
      if (todoIndex !== -1) {
        todos.splice(todoIndex, 1);
        fs.writeFileSync(dataPath, JSON.stringify(todos));
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true }));
      } else {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: false, error: 'TODO item not found' }));
      }
      return;
    }

    res.writeHead(404, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Not Found' }));
  });

  return server;
}

module.exports = createServer;"
    }
  ]
}
